const description = $node['Ollama Vision'].json.response || '';
const story = $node['Ollama Story'].json.response || '';
const audioBuffer = $node['ElevenLabs TTS'].binary.data;
const audioBase64 = audioBuffer ? Buffer.from(audioBuffer.data, 'base64').toString('base64') : '';

return [{
  json: {
    description: description,
    story: story,
    audio: audioBase64
  }
}];
